class Solution {
public:
    int hardestWorker(int n, vector<vector<int>>& logs) {
        int longestTime = 0;
        int hardestWorkerId = -1;
        int prevTime = 0;

        for (auto& log : logs) {
            int id = log[0];
            int leaveTime = log[1];
            int time = leaveTime - prevTime;
            prevTime = leaveTime;

            if (time > longestTime) {
                longestTime = time;
                hardestWorkerId = id;
            } else if (time == longestTime) {
                hardestWorkerId = min(hardestWorkerId, id);
            }
        }

        return hardestWorkerId;
    }
};

